INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3000, "訓練はまだ\nここからですわ", "vo_minigame_1013_icon_1_002_001", "調子が上がって\nきたなっ", 2, 1, "vo_minigame_1013_icon_2_002_001", 1000, 2, 2);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3000, "クスクス、悪くない\n流れですわね", "vo_minigame_1013_icon_1_003_001", "ほらほら、\nまだいけるだろ？", 2, 2, "vo_minigame_1013_icon_2_003_001", 5000, 2, 2);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3000, "すばらしい\n記録ですわ", "vo_minigame_1013_icon_1_004_001", "へへっ、おまえら\nやるじゃねえか！", 2, 3, "vo_minigame_1013_icon_2_004_001", 10000, 2, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3000, "乗りに乗って\nいますわね", "vo_minigame_1013_icon_1_005_001", "あたしたちはまだ\n止まらねえぜ！", 2, 4, "vo_minigame_1013_icon_2_005_001", 10000, 3, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3000, "まだまだ行きます\nついてきなさい", "vo_minigame_1013_icon_1_005_002", "見てろよ！\nマコト班の快進撃だ！", 2, 5, "vo_minigame_1013_icon_2_005_002", 10000, 3, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3000, "エリコ班の\n本領発揮ですわ！", "vo_minigame_1013_icon_1_005_003", "うおぉぉっ！\n絶好調だぜ！", 2, 6, "vo_minigame_1013_icon_2_005_003", 10000, 3, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3000, "ここからは\n前人未到の領域です！", "vo_minigame_1013_icon_1_006_001", "どこまで行けるか\n楽しみだなっ！", 2, 7, "vo_minigame_1013_icon_2_006_001", 0, 4, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1000, "厄介でしたわ…", "vo_minigame_1013_icon_1_007_001", "まだ諦めんなよっ", 3, 8, "vo_minigame_1013_icon_2_007_001", 1, 5, 4);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1000, "油断大敵です", "vo_minigame_1013_icon_1_007_002", "冷やっとしたぜ…！", 3, 9, "vo_minigame_1013_icon_2_007_002", 1, 5, 4);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1000, "忌々しいっ…", "vo_minigame_1013_icon_1_007_003", "弱音を吐くなっ", 3, 10, "vo_minigame_1013_icon_2_007_003", 1, 5, 4);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1500, "大所帯ですわね", "vo_minigame_1013_icon_1_008_001", "マコト班集合！", 4, 11, "vo_minigame_1013_icon_2_008_001", 99, 6, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1500, "エリコ班へようこそ", "vo_minigame_1013_icon_1_008_002", "連携してくぞ！", 4, 12, "vo_minigame_1013_icon_2_008_002", 99, 6, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3000, "ナナカちゃんに\nお任せあれ", "vo_minigame_1013_icon_1_020_001", "みんなに力を！", 1, 13, "vo_minigame_1013_icon_2_020_001", 0, 8, 6);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3000, "はっはっは！\n任せろ！", "vo_minigame_1013_icon_1_022_001", "任せてくれたまえ", 1, 14, "vo_minigame_1013_icon_2_022_001", 0, 9, 7);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3000, "どんどんいくわよ", "vo_minigame_1013_icon_1_023_001", "ほな、いきまひょか", 1, 15, "vo_minigame_1013_icon_2_023_001", 0, 10, 8);
